+    return;
+  }
+
+  console.log(chalk.bold(`Found ${results.length} matches for "${query}":\n`));
+
+  for (const { prompt, score, matchedFields } of results) {
+    console.log(`${chalk.cyan.bold(prompt.title)} ${chalk.dim(`(${prompt.id})`)}`);
